#include <bits/stdc++.h>
using namespace std;
int main(){
    int n,a[200005];
    cin>>n;
    for(int i=1;i<=n;i++)cin>>a[i];
    if(n==2){
    	cout<<min(a[1]%a[2],a[2]%a[1]);
    	return 0;
	}else if(n<2){
		cout<<-1;
		return 0;
	}
    sort(a+1,a+n+1);int t=n-1;
    if(a[t]==a[n]){
        while(a[t]==a[n] && t>0){
            t--;
        }
        if(t<=0){
            cout<<-1;return 0;
        }
    }
    for(int i=t-1;i>=1;i--){
        if(a[i]!=a[t]){cout<<((a[i]>a[n]%a[t])?a[i]:a[n]%a[t]);return 0;}
    }
    cout<<-1;
    return 0;
}
